+List<FractalColorStop> _capPaletteStopsPreservingEndpoint(
+  List<FractalColorStop> stops, {
+  required int maxStops,
+}) {
+  assert(stops.isNotEmpty);
+  return stops.length > maxStops
+      ? [
+          ...stops.take(maxStops - 1),
+          stops.last,
+        ]
+      : stops;
